<?php
$pageTitle='Supplier Price Lists';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('supplier_price_lists');
$pdo=getDB();$suppliers=$pdo->query('SELECT id,supplier_code,company_name FROM '.table('suppliers').' WHERE status="active" ORDER BY company_name LIMIT 400')->fetchAll();$products=$pdo->query('SELECT id,sku,name FROM '.table('products').' WHERE active=1 ORDER BY name LIMIT 500')->fetchAll();$lists=$pdo->query('SELECT pl.*,s.company_name FROM '.table('supplier_price_lists').' pl LEFT JOIN '.table('suppliers').' s ON s.id=pl.supplier_id ORDER BY pl.created_at DESC LIMIT 100')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){try{$action=(string)($_POST['action']??'list');if($action==='item'){$pdo->prepare('INSERT INTO '.table('supplier_price_list_items').' (supplier_price_list_id,product_id,supplier_sku,description,unit_cost,moq,lead_time_days) VALUES (?,?,?,?,?,?,?)')->execute([(int)$_POST['price_list_id'],(int)$_POST['product_id']?:null,trim((string)$_POST['supplier_sku']),trim((string)$_POST['description']),max(0,(float)$_POST['unit_cost']),max(0,(float)$_POST['moq']),max(0,(int)$_POST['lead_time_days'])]);flash('success','Price list item added.');}else{$num=nextScopedDocumentNumber($pdo,'supplier_price_list',setting('supplier_price_list_prefix','SPL'),operationalScope($pdo));$pdo->prepare('INSERT INTO '.table('supplier_price_lists').' (price_list_number,supplier_id,price_list_name,currency,valid_from,valid_to,status,notes) VALUES (?,?,?,?,?,?,"active",?)')->execute([$num,(int)$_POST['supplier_id'],trim((string)$_POST['price_list_name']),trim((string)$_POST['currency']),trim((string)$_POST['valid_from'])?:null,trim((string)$_POST['valid_to'])?:null,trim((string)$_POST['notes'])]);flash('success','Supplier price list created.');}}catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'supplier-price-lists']);flash('error',$e->getMessage());}redirect(ADMIN_URL.'/erp/supplier-price-lists.php');}
$items=$pdo->query('SELECT i.*,pl.price_list_number,p.sku,p.name FROM '.table('supplier_price_list_items').' i LEFT JOIN '.table('supplier_price_lists').' pl ON pl.id=i.supplier_price_list_id LEFT JOIN '.table('products').' p ON p.id=i.product_id ORDER BY i.created_at DESC LIMIT 150')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Supplier Pricing</div><h2 class="h4 mb-1">Supplier Price Lists</h2><p class="text-secondary mb-0">Manage supplier product pricing, MOQ, lead time, and valid purchase cost windows.</p></div></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><h2 class="h5 mb-3">Create Price List</h2><select class="form-select mb-2" name="supplier_id"><?php foreach($suppliers as $s): ?><option value="<?php echo (int)$s['id']; ?>"><?php echo esc($s['supplier_code'].' · '.$s['company_name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="price_list_name" placeholder="Price list name"><input class="form-control mb-2" name="currency" value="<?php echo esc(CURRENCY); ?>"><div class="row g-2"><div class="col-6"><input class="form-control" type="date" name="valid_from"></div><div class="col-6"><input class="form-control" type="date" name="valid_to"></div></div><textarea class="form-control my-3" name="notes" rows="2"></textarea><button class="btn btn-brand w-100">Create List</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="item"><h2 class="h5 mb-3">Add Item</h2><select class="form-select mb-2" name="price_list_id"><?php foreach($lists as $l): ?><option value="<?php echo (int)$l['id']; ?>"><?php echo esc($l['price_list_number'].' · '.$l['company_name']); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="product_id"><option value="0">No mapped product</option><?php foreach($products as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc($p['sku'].' · '.$p['name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="supplier_sku" placeholder="Supplier SKU"><input class="form-control mb-2" name="description" placeholder="Description"><input class="form-control mb-2" type="number" step="0.01" name="unit_cost" placeholder="Unit cost"><input class="form-control mb-2" type="number" step="0.0001" name="moq" placeholder="MOQ"><input class="form-control mb-3" type="number" name="lead_time_days" placeholder="Lead days"><button class="btn btn-outline-primary w-100">Add Item</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Price Lists</h2><table class="table"><thead><tr><th>List</th><th>Supplier</th><th>Valid</th><th>Status</th></tr></thead><tbody><?php foreach($lists as $l): ?><tr><td><strong><?php echo esc($l['price_list_number']); ?></strong><div class="small text-secondary"><?php echo esc($l['price_list_name']); ?></div></td><td><?php echo esc($l['company_name']); ?></td><td><?php echo esc($l['valid_from'].' → '.$l['valid_to']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($l['status'])); ?>"><?php echo esc($l['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Items</h2><table class="table"><thead><tr><th>List</th><th>Product</th><th>Supplier SKU</th><th>Cost</th><th>MOQ</th><th>Lead</th></tr></thead><tbody><?php foreach($items as $i): ?><tr><td><?php echo esc($i['price_list_number']); ?></td><td><?php echo esc(($i['sku']?:'').($i['name']?' · '.$i['name']:$i['description'])); ?></td><td><?php echo esc($i['supplier_sku']); ?></td><td><?php echo money($i['unit_cost']); ?></td><td><?php echo number_format((float)$i['moq'],4); ?></td><td><?php echo (int)$i['lead_time_days']; ?> days</td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>